+var emailsClassifyAutoCmd = &cobra.Command{
+	Use:   "classify-auto",
+	Short: "Auto-classify obvious emails with heuristics (no AI needed)",
+	Long: `Applies deterministic rules to classify unclassified emails:
+  - Same domain as sender → internal
+  - noreply/no-reply addresses → transactional
+  - Newsletter/unsubscribe signals → newsletter
+  - Personal domain to personal domain → personal
+
+Returns a summary of what was classified and how many remain for Claude.`,
